// PulsightInternalCoreUsecasesBacktestBacktestSummary defines model for pulsight_internal_core_usecases_backtest.BacktestSummary.
type PulsightInternalCoreUsecasesBacktestBacktestSummary struct {
	EndingBalanceSol *float32 `json:"ending_balance_sol,omitempty"`
	FeesPaidSol      *float32 `json:"fees_paid_sol,omitempty"`

	// HeldPositions HeldPositions is every mint still open at run end — the bags the
	// strategy never sold, valued at their liquidity-aware exit (see
	// BacktestPosition). Their UnrealizedPnlSol sums into UnrealizedPnlSol
	// above. Empty when the strategy closed everything (all "Sold all").
	// Additive JSONB field — pre-existing rows decode as nil.
	HeldPositions  *[]PulsightInternalCoreUsecasesBacktestBacktestPosition `json:"held_positions,omitempty"`
	Losses         *int                                                    `json:"losses,omitempty"`
	MaxDrawdownSol *float32                                                `json:"max_drawdown_sol,omitempty"`

	// OurAvgPriceImpactPct Price-impact rollups, in percent of mid. "Our*" averages over every
	// simulated trade that had a pool snapshot; "Target*" averages over the
	// copy trades that mirrored a target swap 1:1 (same timestamp). Zero when
	// no trade contributed (e.g. an indicator-only strategy, or a run with no
	// pool data). Additive JSONB fields — pre-existing rows decode as 0.
	OurAvgPriceImpactPct    *float32 `json:"our_avg_price_impact_pct,omitempty"`
	OurMedianPriceImpactPct *float32 `json:"our_median_price_impact_pct,omitempty"`
	RealizedPnlSol          *float32 `json:"realized_pnl_sol,omitempty"`
	RoiPct                  *float32 `json:"roi_pct,omitempty"`

	// SimulationAssumptions SimulationAssumptions is free-text notes about which real-world
	// cost components the simulator did NOT model (route hops, MEV,
	// partial fills, pre-trade gas estimation, etc.). Rendered
	// prominently on the result page so users don't read "won 4.2 SOL"
	// too literally.
	SimulationAssumptions      *[]string `json:"simulation_assumptions,omitempty"`
	StartingBalanceSol         *float32  `json:"starting_balance_sol,omitempty"`
	TargetAvgPriceImpactPct    *float32  `json:"target_avg_price_impact_pct,omitempty"`
	TargetMedianPriceImpactPct *float32  `json:"target_median_price_impact_pct,omitempty"`
	TipsPaidSol                *float32  `json:"tips_paid_sol,omitempty"`
	TotalPnlSol                *float32  `json:"total_pnl_sol,omitempty"`
	Trades                     *int      `json:"trades,omitempty"`
	UnrealizedPnlSol           *float32  `json:"unrealized_pnl_sol,omitempty"`
	Wins                       *int      `json:"wins,omitempty"`
}

// PulsightInternalCoreUsecasesBacktestBacktestTrade defines model for pulsight_internal_core_usecases_backtest.BacktestTrade.
type PulsightInternalCoreUsecasesBacktestBacktestTrade struct {
	BacktestId       *string  `json:"backtest_id,omitempty"`
	FeeSol           *float32 `json:"fee_sol,omitempty"`
	Idx              *int     `json:"idx,omitempty"`
	Mint             *string  `json:"mint,omitempty"`
	PoolSolAtTrigger *float32 `json:"pool_sol_at_trigger,omitempty"`

	// PriceImpactPct PriceImpactPct is OUR own price impact on this fill, as a percent of the
	// mid price (size / pool_sol, the constant-product average-fill premium).
	// Nil when the engine had no pool snapshot at the tick (impact unknown →
	// pricing degraded to slippage-only). A buy moves price up, a sell down;
	// the magnitude is recorded either way.
	PriceImpactPct *float32                                         `json:"price_impact_pct,omitempty"`
	PricePerToken  *float32                                         `json:"price_per_token,omitempty"`
	RealizedPnlSol *float32                                         `json:"realized_pnl_sol,omitempty"`
	Side           *PulsightInternalCoreUsecasesBacktestSide        `json:"side,omitempty"`
	SolAmount      *float32                                         `json:"sol_amount,omitempty"`
	Source         *PulsightInternalCoreUsecasesBacktestTradeSource `json:"source,omitempty"`

	// TargetPriceImpactPct TargetPriceImpactPct is the MIRRORED trader's own price impact on the
	// swap we copied — set only on copy trades that executed at the same
	// timestamp as the target (a true 1:1 mirror), where the target's move is
	// folded into our fill price. Nil for emit trades and delayed copies.
	TargetPriceImpactPct *float32 `json:"target_price_impact_pct,omitempty"`
	TipSol               *float32 `json:"tip_sol,omitempty"`
	TokenAmount          *float32 `json:"token_amount,omitempty"`
	TriggeringSwapSig    *string  `json:"triggering_swap_sig,omitempty"`
	Ts                   *string  `json:"ts,omitempty"`
}

